#!/bin/bash

# 该脚本从 proto/user.cmd.proto 中提取消息定义，并生成 main/register.message.go。

scriptDir=$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)
serverPath=$(cd "${scriptDir}/../.." && pwd)
simulatorPath="src/client.simulator"
protoPath="${1:-proto}"
inputProto="${protoPath}/user.cmd.proto"
outputGo="${simulatorPath}/main/register.message.go"

cd "${serverPath}" || exit 1

if [ ! -f "${inputProto}" ]; then
    echo -e "\e[91m proto file not found: ${inputProto}\e[0m"
    exit 1
fi

cat > "${outputGo}" <<'GOEOF'
// Code generated by gen.register.message.sh. DO NOT EDIT.

package main

import (
	pb "server/proto/pb"

	xcontrol "github.com/75912001/xlib/control"
	xmessage "github.com/75912001/xlib/message"
	"google.golang.org/protobuf/proto"
)

var GMessage = xmessage.NewMgr()

func init() {
	registerMessages()
}

func registerMessages() {
GOEOF

grep -E '^[[:space:]]+[A-Za-z0-9]+_CMD[[:space:]]*=' "${inputProto}" |
while read -r line; do
    enumName=$(echo "${line}" | sed -E 's/^[[:space:]]*([A-Za-z0-9]+)_CMD[[:space:]]*=.*/\1/')
    if [ "${enumName}" = "UserMsgIDUnknown" ]; then
        continue
    fi
    cat >> "${outputGo}" <<GOEOF
	registerMessage(uint32(pb.MsgIDUser_${enumName}_CMD), func() proto.Message { return &pb.${enumName}{} })
GOEOF
done

cat >> "${outputGo}" <<'GOEOF'
}

func registerMessage(messageID uint32, newProtoMessage func() proto.Message) {
	GMessage.Register(messageID, xmessage.NewOptions().
		WithHandler(xcontrol.NewCallBack(func(args ...any) error { return nil })).
		WithNewProtoMessage(newProtoMessage))
}
GOEOF

gofmt -w "${outputGo}"
echo -e "\e[92m generate register.message.go successfully: ${outputGo}\e[0m"
exit 0
